using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Moq;

namespace ContosoUniversity.Tests.Helpers;

internal static class TestHelper
{
    public static SchoolContext CreateContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static void DrainNotificationQueue()
    {
        using var service = new Services.NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    public static void SetupControllerContext(Controller controller)
    {
        var httpContext = new DefaultHttpContext();
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = httpContext
        };
        controller.TempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());
    }

    public static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2022-09-01") }
        );
        context.SaveChanges();
    }

    public static void SeedDepartments(SchoolContext context)
    {
        context.Departments.AddRange(
            new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") },
            new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") }
        );
        context.SaveChanges();
    }

    public static void SeedCourses(SchoolContext context)
    {
        if (!context.Departments.Any())
        {
            SeedDepartments(context);
        }
        var deptId = context.Departments.First().DepartmentID;
        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = deptId },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = deptId }
        );
        context.SaveChanges();
    }

    public static void SeedInstructors(SchoolContext context)
    {
        context.Instructors.AddRange(
            new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>()
            },
            new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>()
            }
        );
        context.SaveChanges();
    }

    public static void SeedFullInstructorData(SchoolContext context)
    {
        SeedDepartments(context);
        var deptId = context.Departments.First().DepartmentID;

        var courses = new[]
        {
            new Course { CourseID = 2001, Title = "Algebra", Credits = 3, DepartmentID = deptId, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
            new Course { CourseID = 2002, Title = "Geometry", Credits = 4, DepartmentID = deptId, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() }
        };
        context.Courses.AddRange(courses);
        context.SaveChanges();

        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        context.CourseAssignments.Add(new CourseAssignment
        {
            InstructorID = instructor.ID,
            CourseID = 2001
        });
        context.SaveChanges();
    }
}

