using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any existing notifications from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_CreateOperation_EnqueuesWithCorrectProperties()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesUpdateMessage()
    {
        // Act
        _sut.SendNotification("Course", "42", "Chemistry", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
    {
        // Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_CreateWithDisplayName_GeneratesCreateMessage()
    {
        // Act
        _sut.SendNotification("Student", "10", "John Doe", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "99", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 99) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithNullDisplayName_UsesEntityIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "99", null, EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student (ID: 99) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesEntityIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "99", "  ", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student (ID: 99) has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        // Act
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before);
        Assert.IsTrue(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_WithNotification_ReturnsAndDequeues()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act
        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleNotifications_ReturnsFIFOOrder()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Department", "3", EntityOperation.DELETE);

        // Act
        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("Student", first.EntityType);
        Assert.AreEqual("1", first.EntityId);
        Assert.AreEqual("Course", second.EntityType);
        Assert.AreEqual("2", second.EntityId);
        Assert.AreEqual("Department", third.EntityType);
        Assert.AreEqual("3", third.EntityId);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op, just verify no exception
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student (ID: 1) has been created", DisplayName = "CREATE operation")]
    [DataRow(EntityOperation.UPDATE, "Student (ID: 1) has been updated", DisplayName = "UPDATE operation")]
    [DataRow(EntityOperation.DELETE, "Student (ID: 1) has been deleted", DisplayName = "DELETE operation")]
    public void SendNotification_VariousOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        // Act
        _sut.SendNotification("Student", "1", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    public void SendNotification_OverloadWithoutDisplayName_DelegatesToOverloadWithNull()
    {
        // Act
        _sut.SendNotification("Instructor", "7", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor", notification.EntityType);
        Assert.AreEqual("7", notification.EntityId);
        Assert.AreEqual("Instructor (ID: 7) has been updated", notification.Message);
    }
}

