        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_SetsTotalPages_ExactDivision()
    {
        // 20 items, 5 per page = 4 pages
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 1, 5);

        Assert.AreEqual(4, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_SetsTotalPages_RoundsUp()
    {
        // 21 items, 5 per page = 5 pages (rounds up)
        var list = new PaginatedList<int>(new List<int> { 1 }, 21, 1, 5);

        Assert.AreEqual(5, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };
        var list = new PaginatedList<string>(items, 10, 1, 5);

        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("a", list[0]);
        Assert.AreEqual("b", list[1]);
        Assert.AreEqual("c", list[2]);
    }

    [TestMethod]
    public void Constructor_EmptyItems_CreatesEmptyList()
    {
        var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);

        Assert.AreEqual(0, list.Count);
        Assert.AreEqual(1, list.PageIndex);
        Assert.AreEqual(0, list.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_PageOne_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 1, 5);

        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_PageTwo_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 2, 5);

        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 4, 5);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 20, 2, 5);

        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasPreviousPage_HasNextPage_SinglePage_BothFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1, 2 }, 2, 1, 10);

        Assert.IsFalse(list.HasPreviousPage);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ContainsCorrectItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
    }

    [TestMethod]
    public void Create_MiddlePage_ContainsCorrectItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ContainsRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
    }

    [TestMethod]
    public void Create_SingleItem_SinglePage()
    {
        var source = new List<string> { "only" }.AsQueryable();

        var result = PaginatedList<string>.Create(source, 1, 10);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(1, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual("only", result[0]);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    [DataRow(1, false, true, DisplayName = "First page of 3")]
    [DataRow(2, true, true, DisplayName = "Middle page of 3")]
    [DataRow(3, true, false, DisplayName = "Last page of 3")]
    public void Create_VariousPages_CorrectNavigationFlags(int pageIndex, bool expectedHasPrev, bool expectedHasNext)
    {
        var source = Enumerable.Range(1, 30).AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex, 10);

        Assert.AreEqual(expectedHasPrev, result.HasPreviousPage);
        Assert.AreEqual(expectedHasNext, result.HasNextPage);
    }
}

