using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class ModelTests
{
    // ── Person.FullName ──

    [TestMethod]
    public void Person_FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student { LastName = "Smith", FirstMidName = "John" };

        Assert.AreEqual("Smith, John", student.FullName);
    }

    [TestMethod]
    [DataRow("Alexander", "Carson", "Alexander, Carson", DisplayName = "Standard name")]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
    [DataRow("Li", "Yan", "Li, Yan", DisplayName = "Short names")]
    public void Person_FullName_VariousNames_FormatsCorrectly(string lastName, string firstName, string expected)
    {
        var instructor = new Instructor { LastName = lastName, FirstMidName = firstName };

        Assert.AreEqual(expected, instructor.FullName);
    }

    // ── ErrorViewModel ──

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_WithValue_ReturnsTrue()
    {
        var model = new ErrorViewModel { RequestId = "abc123" };

        Assert.IsTrue(model.ShowRequestId);
    }

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_Null_ReturnsFalse()
    {
        var model = new ErrorViewModel { RequestId = null };

        Assert.IsFalse(model.ShowRequestId);
    }

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_Empty_ReturnsFalse()
    {
        var model = new ErrorViewModel { RequestId = "" };

        Assert.IsFalse(model.ShowRequestId);
    }

    // ── Student ──

    [TestMethod]
    public void Student_InheritsFromPerson()
    {
        var student = new Student();

        Assert.IsInstanceOfType<Person>(student);
    }

    [TestMethod]
    public void Student_EnrollmentDate_CanBeSet()
    {
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };

        Assert.AreEqual(date, student.EnrollmentDate);
    }

    // ── Instructor ──

    [TestMethod]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor();

        Assert.IsInstanceOfType<Person>(instructor);
    }

    [TestMethod]
    public void Instructor_HireDate_CanBeSet()
    {
        var date = new DateTime(2000, 3, 15);
        var instructor = new Instructor { HireDate = date };

        Assert.AreEqual(date, instructor.HireDate);
    }

    // ── Course ──

    [TestMethod]
    public void Course_Properties_CanBeSetAndRead()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/chem.jpg"
        };

        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/images/chem.jpg", course.TeachingMaterialImagePath);
    }

    // ── Department ──

    [TestMethod]
    public void Department_Properties_CanBeSetAndRead()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 5
        };

        Assert.AreEqual(1, dept.DepartmentID);
        Assert.AreEqual("Engineering", dept.Name);
        Assert.AreEqual(350000m, dept.Budget);
        Assert.AreEqual(new DateTime(2007, 9, 1), dept.StartDate);
        Assert.AreEqual(5, dept.InstructorID);
    }

    [TestMethod]
    public void Department_InstructorID_CanBeNull()
    {
        var dept = new Department { InstructorID = null };

        Assert.IsNull(dept.InstructorID);
    }

    // ── Enrollment ──

    [TestMethod]
    public void Enrollment_Grade_CanBeNull()
    {
        var enrollment = new Enrollment { Grade = null };

        Assert.IsNull(enrollment.Grade);
    }

    [TestMethod]
    [DataRow(Grade.A, DisplayName = "Grade A")]
    [DataRow(Grade.B, DisplayName = "Grade B")]
    [DataRow(Grade.C, DisplayName = "Grade C")]
    [DataRow(Grade.D, DisplayName = "Grade D")]
    [DataRow(Grade.F, DisplayName = "Grade F")]
