using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    [TestInitialize]
    public void Setup()
    {
        TestHelper.DrainNotificationQueue();
    }

    private StudentsController CreateController(Data.SchoolContext context)
    {
        var controller = new StudentsController(context);
        TestHelper.SetupControllerContext(controller);
        return controller;
    }

    // ── Index ──

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithAllStudents()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedStudents(context);
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedStudents(context);
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null, null, null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedStudents(context);
        using var controller = CreateController(context);

        // Act
        var result = controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Anand", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Alexander", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedStudents(context);
        using var controller = CreateController(context);

        // Act
        var result = controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // 2020 < 2021 < 2022
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
