using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    [TestInitialize]
    public void Setup()
    {
        TestHelper.DrainNotificationQueue();
    }

    private InstructorsController CreateController(SchoolContext context)
    {
        var controller = new InstructorsController(context);
        TestHelper.SetupControllerContext(controller);
        return controller;
    }

    // ── Index ──

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedFullInstructorData(context);
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Instructors.Any());
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsCourses()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedFullInstructorData(context);
        var instructor = context.Instructors
            .Include(i => i.CourseAssignments)
            .First(i => i.CourseAssignments.Any());
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(instructor.ID, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.IsTrue(model.Courses.Any());
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyInstructors()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsFalse(model.Instructors.Any());
    }

    // ── Details ──

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_NonExistentId_ReturnsNotFound()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Details(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedInstructors(context);
        var instructor = context.Instructors.First();
        using var controller = CreateController(context);

        // Act
        var result = controller.Details(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.LastName, model.LastName);
        Assert.AreEqual(instructor.FirstMidName, model.FirstMidName);
    }

    // ── Create GET ──

    [TestMethod]
    public void Create_GET_ReturnsViewWithInstructor()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedCourses(context);
