    }

    [TestMethod]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedCourses(context);
        using var controller = CreateController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            FirstMidName = "Jane",
            HireDate = DateTime.Parse("2020-01-15")
        };

        // Act
        var result = controller.Create(instructor, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(0, context.Instructors.Count());
        // Verify PopulateAssignedCourseData was called
        Assert.IsNotNull(controller.ViewBag.Courses);
    }

    // ── Edit GET ──

    [TestMethod]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Edit((int?)null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_GET_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedFullInstructorData(context);
        var instructor = context.Instructors
            .Include(i => i.CourseAssignments)
                .ThenInclude(c => c.Course)
            .Include(i => i.OfficeAssignment)
            .First();
        using var controller = CreateController(context);

        // Act
        var result = controller.Edit((int?)instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.LastName, model.LastName);
        Assert.IsNotNull(controller.ViewBag.Courses);
    }

    // ── Edit POST ──

    [TestMethod]
    public async Task Edit_POST_NullId_ReturnsBadRequest()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = await controller.Edit((int?)null, null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

