        // Act
        var result = controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_GET_NonExistentId_ReturnsNotFound()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_GET_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedInstructors(context);
        var instructor = context.Instructors.First();
        using var controller = CreateController(context);

        // Act
        var result = controller.Delete(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.LastName, model.LastName);
    }

    // ── Delete POST ──

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        TestHelper.SeedFullInstructorData(context);
        var instructor = context.Instructors
            .Include(i => i.OfficeAssignment)
            .First();
        var instructorId = instructor.ID;
        using var controller = CreateController(context);

        // Act
        var result = controller.DeleteConfirmed(instructorId) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.IsNull(context.Instructors.Find(instructorId));
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorIsDepartmentAdmin_ClearsDepartmentInstructorId()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        var instructor = new Instructor
        {
            FirstMidName = "Admin",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2000-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var department = new Department
        {
            Name = "TestDept",
            Budget = 100000m,
            StartDate = DateTime.Parse("2007-01-01"),
            InstructorID = instructor.ID
        };
        context.Departments.Add(department);
        context.SaveChanges();

        // Add an OfficeAssignment so the Include doesn't fail
        context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Room 101"
        });
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act
        controller.DeleteConfirmed(instructor.ID);

        // Assert
        var updatedDept = context.Departments.Find(department.DepartmentID);
        Assert.IsNotNull(updatedDept);
        Assert.IsNull(updatedDept.InstructorID);
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorNotDepartmentAdmin_DoesNotAffectDepartment()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        var instructor1 = new Instructor
        {
            FirstMidName = "Admin",
            LastName = "First",
            HireDate = DateTime.Parse("2000-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        var instructor2 = new Instructor
        {
            FirstMidName = "Other",
            LastName = "Second",
            HireDate = DateTime.Parse("2001-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        var department = new Department
        {
            Name = "TestDept",
            Budget = 100000m,
            StartDate = DateTime.Parse("2007-01-01"),
            InstructorID = instructor1.ID
        };
        context.Departments.Add(department);
        context.SaveChanges();

        using var controller = CreateController(context);

        // Act - delete instructor2 who is NOT the department admin
        controller.DeleteConfirmed(instructor2.ID);

        // Assert
        var updatedDept = context.Departments.Find(department.DepartmentID);
        Assert.IsNotNull(updatedDept);
        Assert.AreEqual(instructor1.ID, updatedDept.InstructorID);
    }
}

