using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    [TestInitialize]
    public void Setup()
    {
        TestHelper.DrainNotificationQueue();
    }

    private NotificationsController CreateController(SchoolContext context)
    {
        var controller = new NotificationsController(context);
        TestHelper.SetupControllerContext(controller);
        return controller;
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        // Check the anonymous type's properties via reflection
        var value = jsonResult.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));
        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotificationsFromQueue()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);
        // Enqueue notifications via the service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John", EntityOperation.CREATE);
        service.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

        // Act
        var result = controller.GetNotifications() as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(2, countProp.GetValue(value));
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10Notifications()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = controller.GetNotifications() as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_DrainsQueue_SecondCallReturnsRemaining()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Act - first call gets 10
        var result1 = controller.GetNotifications() as JsonResult;
        var count1 = result1.Value.GetType().GetProperty("count").GetValue(result1.Value);

        // Act - second call gets remaining 5
        var result2 = controller.GetNotifications() as JsonResult;
        var count2 = result2.Value.GetType().GetProperty("count").GetValue(result2.Value);

        // Assert
        Assert.AreEqual(10, count1);
        Assert.AreEqual(5, count2);
    }

    [TestMethod]
    public void MarkAsRead_ValidId_ReturnsSuccess()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.MarkAsRead(1) as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_AnyId_ReturnsSuccess()
    {
        // Arrange - MarkAsRead is a no-op, so any ID should succeed
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result1 = controller.MarkAsRead(0) as JsonResult;
        var result2 = controller.MarkAsRead(-1) as JsonResult;
        var result3 = controller.MarkAsRead(int.MaxValue) as JsonResult;

        // Assert
        Assert.IsNotNull(result1);
        Assert.IsNotNull(result2);
        Assert.IsNotNull(result3);
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Arrange
        var context = TestHelper.CreateContext();
        using var controller = CreateController(context);

        // Act
        var result = controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }
}

